/* InternshipCard.jsx */
import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import './InternshipCard.css';

export default function InternshipCard({ internship, variant = 'default' }) {
  const { id, role, company, logo, logoColor, location, remote, stipend,
          duration, tags, tagColor, description, openings, featured } = internship;

  const [applied, setApplied] = useState(false);

  const handleApply = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setApplied(true);
  };

  return (
    <Link to={`/internships/${id}`} className={`icard icard--${variant}`}>
      {/* Header Row — logo + meta only, badges moved below */}
      <div className="icard__header">
        <div className="icard__logo" style={{ '--logo-color': logoColor }}>
          {logo}
        </div>
        <div className="icard__meta">
          <h4 className="icard__role">{role}</h4>
          <span className="icard__company">{company}</span>
        </div>
      </div>

      {/* Badge row — FEATURED + REMOTE separated cleanly */}
      <div className="icard__badges">
        {featured && (
          <span className="icard__badge icard__badge--featured">Featured</span>
        )}
        <span className={`icard__remote-badge ${remote ? 'icard__remote-badge--yes' : ''}`}>
          {remote ? '🌐 Remote' : `📍 ${location}`}
        </span>
      </div>

      {/* Description */}
      {variant !== 'compact' && (
        <p className="icard__desc">{description}</p>
      )}

      {/* Tags */}
      <div className="icard__tags">
        {tags.map(tag => (
          <span key={tag} className={`tag tag-${tagColor}`}>{tag}</span>
        ))}
      </div>

      {/* Footer */}
      <div className="icard__footer">
        <div className="icard__stats">
          <span className="icard__stat">
            <span className="icard__stat-icon">💰</span>
            ₹{stipend.toLocaleString()}/mo
          </span>
          <span className="icard__stat">
            <span className="icard__stat-icon">📅</span>
            {duration}
          </span>
          <span className="icard__stat">
            <span className="icard__stat-icon">👥</span>
            {openings} opening{openings > 1 ? 's' : ''}
          </span>
        </div>

        {/* Apply button — replaces "View →" */}
        <button
          className={`icard__apply-btn ${applied ? 'icard__apply-btn--applied' : ''}`}
          onClick={handleApply}
        >
          {applied ? '✓ Applied' : 'Apply'}
        </button>
      </div>
    </Link>
  );
}
